import bisect


class TopVotedCandidate:
    def __init__(self, persons, times):
        self.times = times
        self.leaders = []
        counts = {}
        leader = -1
        best = 0
        for p in persons:
            counts[p] = counts.get(p, 0) + 1
            if counts[p] >= best:
                best = counts[p]
                leader = p
            self.leaders.append(leader)
    def q(self, t):
        i = bisect.bisect_right(self.times, t) - 1
        return self.leaders[i]

