var TopVotedCandidate = function(persons, times) {
    this.times = times;
    this.leaders = [];
    const counts = new Map();
    let leader = -1, best = 0;
    for (const p of persons) {
        const c = (counts.get(p) || 0) + 1;
        counts.set(p, c);
        if (c >= best) { best = c; leader = p; }
        this.leaders.push(leader);
    }
};
TopVotedCandidate.prototype.q = function(t) {
    let lo = 0, hi = this.times.length - 1, ans = 0;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (this.times[mid] <= t) { ans = mid; lo = mid + 1; }
        else hi = mid - 1;
    }
    return this.leaders[ans];
};
